async function startServer() {
  const app = express();
  const PORT = 3000;

  // Body parsers
  app.use(express.json());

  // API Route: Dynamic Clues (Offline Static Country Profiles + Gemini Dynamic Translation)
  app.post("/api/clues", async (req: Request, res: Response): Promise<void> => {
    try {
      const { lat, lng, locationId, clueIndex } = req.body;

      if (typeof lat !== 'number' || typeof lng !== 'number') {
        res.status(400).json({ error: "Parâmetros lat e lng inválidos." });
        return;
      }

      let countryProfile: CountryProfile | null = null;
      let countryCode = "br";

      // 1. First attempt: Match using locationId sent by the client
      if (locationId && typeof locationId === "string") {
        const code = LOCATION_TO_COUNTRY_MAP[locationId];
        if (code && COUNTRY_FACTS_BASE[code]) {
          countryCode = code;
          countryProfile = COUNTRY_FACTS_BASE[code];
        }
      }

      // 2. Second attempt: Coordinate-based proximity match (100% offline fallback to avoid REST Countries/Nominatim rate blocks)
      if (!countryProfile) {
        let minDistance = Infinity;
        let bestMatch = GAME_LOCATIONS_COORDS[0];

        for (const loc of GAME_LOCATIONS_COORDS) {
          const dist = Math.hypot(loc.lat - lat, loc.lng - lng);
          if (dist < minDistance) {
            minDistance = dist;
            bestMatch = loc;
          }
        }

        // Within 3 degrees is a very safe coordinate-proximity matching window
        if (minDistance < 3.0 && COUNTRY_FACTS_BASE[bestMatch.country]) {
          countryCode = bestMatch.country;
          countryProfile = COUNTRY_FACTS_BASE[bestMatch.country];
        }
      }

      // 3. Third attempt (Dynamic Fallback): Reverse Geocode via OpenStreetMap Nominatim
      if (!countryProfile) {
        const nominatimUrl = `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}&zoom=5&addressdetails=1`;
        let countryNameFromOSM = "";

        try {
          const osmRes = await fetch(nominatimUrl, {
            headers: {
              "User-Agent": "GeoGuessrMapillaryClone/1.0 (tl.andrade.2024@aluno.unila.edu.br)"
            }
          });
          if (osmRes.ok) {
            const osmData = await osmRes.json();
            const extractedCode = (osmData.address?.country_code || "").toLowerCase();
            if (extractedCode) {
              countryCode = extractedCode;
            }
            countryNameFromOSM = osmData.address?.country || "";
          }
        } catch (osmErr) {
          console.error("Erro ao consultar Nominatim:", osmErr);
        }

        // Check if we have an offline static profile for this extracted country code
        if (COUNTRY_FACTS_BASE[countryCode]) {
          countryProfile = COUNTRY_FACTS_BASE[countryCode];
        } else {
          // If no offline profile exists for this new country, fetch from REST Countries API
          const countriesUrl = `https://restcountries.com/v3.1/alpha/${countryCode}?fields=name,continents,subregion,car,idd,currencies,tld,languages`;
          let apiFacts: any = null;

          try {
            const rcRes = await fetch(countriesUrl);
            if (rcRes.ok) {
              const rcData = await rcRes.json();
              apiFacts = Array.isArray(rcData) ? rcData[0] : rcData;
            }
          } catch (rcErr) {
            console.error("Erro ao consultar REST Countries:", rcErr);
          }

          if (apiFacts) {
            const continent = (apiFacts.continents || []).join(", ") || "Desconhecido";
            const subregion = apiFacts.subregion || "Desconhecido";
            const driveSide = apiFacts.car?.side === "left" ? "lado esquerdo (mão inglesa)" : "lado direito (padrão)";
            
            const callingCodeRoot = apiFacts.idd?.root || "";
            const callingCodeSuffix = (apiFacts.idd?.suffixes || [])[0] || "";
            const callingCode = callingCodeRoot + callingCodeSuffix || "Desconhecido";

            const currencyKeys = Object.keys(apiFacts.currencies || {});
            const currencyObj = currencyKeys.length > 0 ? apiFacts.currencies[currencyKeys[0]] : null;
            const currencyName = currencyObj ? `${currencyObj.name} (${currencyObj.symbol || ''})` : "Desconhecida";
            
            const tld = (apiFacts.tld || []).join(", ") || "Desconhecido";
            const languages = Object.values(apiFacts.languages || {}).join(", ") || "Desconhecido";
            const countryOfficialName = apiFacts.name?.official || apiFacts.name?.common || countryNameFromOSM || "este local";

            countryProfile = {
              name: countryNameFromOSM || countryOfficialName,
              officialName: countryOfficialName,
              continent,
              subregion,
              driveSide,
              callingCode,
              currencyName,
              tld,
              languages,
              funFacts: [
                `Este local está no continente ${continent}, mais especificamente na sub-região de ${subregion}.`,
                `O tráfego de veículos flui pelo ${driveSide}, e o código de discagem direta internacional é ${callingCode}.`,
                `A economia utiliza a moeda ${currencyName}, e o sufixo nacional de domínio virtual é ${tld}.`
              ]
            };
          }
        }
      }

      // 4. Absolute Fallback: Default profile if all else failed to prevent undefined variables
      if (!countryProfile) {
        countryProfile = {
          name: "este local",
          officialName: "este local",
          continent: "Ásia/Europa",
          subregion: "Região Central",
          driveSide: "lado direito (padrão)",
          callingCode: "Desconhecido",
          currencyName: "Moeda Local",
          tld: ".org",
          languages: "Idioma Regional",
          funFacts: [
            "Um belo destino cercado por arquiteturas típicas e paisagens inconfundíveis.",
            "Uma região vibrante repleta de características culturais singulares e ricas.",
            "Um ponto estratégico importante com infraestrutura de transporte e conectividade dinâmica."
          ]
        };
      }

      // Prepare support guides and base facts
      let targetFactForBackup = countryProfile.funFacts[clueIndex % countryProfile.funFacts.length];

      if (clueIndex < 0 || clueIndex > 3) {
        res.status(400).json({ error: "Código de dica inválido." });
        return;
      }

      // Robust fallback text generator (Offline Static Clue Profile Backup)
      // Styled gracefully without rigid category headers or direct giveaways (DDI, TLDs, explicit names)
      const getFallbackClueText = () => {
        if (clueIndex === 0) return `Este canto do mundo fica localizado no continente ${countryProfile!.continent} (na sub-região de ${countryProfile!.subregion}). ${targetFactForBackup}`;
        if (clueIndex === 1) return `Observando a movimentação urbana por aqui, os automóveis circulam pelo ${countryProfile!.driveSide} da pista. ${targetFactForBackup}`;
        if (clueIndex === 2) return `A nível comercial, as transações locais são mediadas por uma moeda específica desta parte do globo, enquanto sua soberania digital na rede é representada por um domínio nacional exclusivo de internet. ${targetFactForBackup}`;
        if (clueIndex === 3) return `Entre a população nativa, as tradições locais e a herança linguística expressam a identidade singular desta nação. ${targetFactForBackup}`;
        return "Informações sobre este local não estão disponíveis no momento.";
      };

      // Select a varied stylistic model to make AI generate different guides and style tones
      const selectedStyleModel = MODELOS_DE_GUIA_BASE[clueIndex % MODELOS_DE_GUIA_BASE.length];

      let generatedClue = "";
      let isFallback = false;

      // Generate dynamic, high-quality, completely non-hallucinatory clue using Gemini-3.5-flash
      if (!process.env.GEMINI_API_KEY || process.env.GEMINI_API_KEY === "MY_GEMINI_API_KEY") {
        generatedClue = getFallbackClueText();
        isFallback = true;
      } else {
        try {
          const systemInstruction = 
            `Você é uma Inteligência Artificial especializada em criar pistas enigmáticas, envolventes e altamente precisas para um jogo de adivinhação geográfica em português do Brasil.
            
            Sua tarefa é ler dados reais de um país e redigir uma pista instigante com base em um estilo de guia estruturado, respondendo à solicitação do usuário.
            
            DIRETRIZ CRÍTICA DE PREVENÇÃO DE ALUCINAÇÕES (EVITAR ERROS):
            - Baseie sua pista estritamente nos dados fáticos fornecidos no prompt.
            - Nunca invente fatos, climas fictícios, características geográficas falsas, pratos típicos falsos, ou informações de tráfego que não estejam contidas nos dados fáticos ou nas curiosidades fornecidas.
            - Se um dado estiver marcado como "Desconhecido" ou "não disponível", você NÃO deve usá-lo na pista de forma alguma.
            
            DIRETRIZ DE NÃO-REVELAÇÃO E SIGILO EXTREMO (SEM SPOILERS DIRETOS):
            1. É terminantemente PROIBIDO revelar ou mencionar o nome do país (${countryProfile.name} ou ${countryProfile.officialName}), capitais ou cidades do país no texto final da pista.
            2. É expressamente PROIBIDO citar qualquer código telefônico de país/DDI (como por exemplo "+358", "+45", "+31", ou "prefixo de telefone 35"). Nunca insira esses números!
            3. É expressamente PROIBIDO citar o domínio nacional de internet de nível superior (TLD, como por exemplo ".fi", ".dk", ".nl", ".ie"). Nunca insira estas siglas!
            4. É expressamente PROIBIDO citar o nome literal de moedas ou idiomas que contenham o próprio nome do país ou que sejam extremamente óbvios (por exemplo: em vez de "Coroa Dinamarquesa", use "a coroa local"; em vez de "Peso Chileno", use "a moeda própria chilena" ou "o peso local"; em vez de "Iene Japonês", use "a moeda asiática tradicional").
            5. Nunca escreva o nome de idiomas derivados diretamente do nome do país (por exemplo: não use "dinamarquês", "holandês", "irlandês", "japonês", "francês", "alemão", "espanhol", "italiano"). Em vez disso, use descrições literárias elegantes como "o idioma oficial falado localmente", "a expressiva língua germânica da região", "um idioma de origem eslava/latina", etc.
            6. Use expressões neutras para referir-se à localidade, como: "este território", "esta nação", "este canto do globo", "este lugar", "por aqui", etc.`;

          // A focused perspective for each index ensures we cover geographical, gastronomic, general knowledge or cultural aspects of the place
          const focusAspect = clueIndex === 0 
            ? "Geografia Física, Clima ou Relevo" 
            : clueIndex === 1 
            ? "Cultura, Hábitos locais ou Curiosidades tradicionais" 
            : clueIndex === 2 
            ? "Gastronomia típica, Culinária local, Pratos tradicionais ou Sabores regionais" 
            : "Conhecimentos Gerais, História ou Arquitetura característica";

          const promptText = 
            `### DIRETRIZ DE ENTRADA DO USUÁRIO:
            "Escreva em poucas palavras uma pista geográfica, gastronômica, de conhecimentos gerais ou cultural desse lugar, sem revelar o lugar em si."

            ### DADOS FÁTICOS REAIS DO PAÍS REVELADO DO JOGO (USE APENAS ESTES FATOS PARA CONSTRUIR A PISTA, NÃO INVENTE NADA):
            - Nome: ${countryProfile.name}
            - Nome Oficial: ${countryProfile.officialName}
            - Continente: ${countryProfile.continent}
            - Sub-região: ${countryProfile.subregion}
            - Mão de Direção (Lado da pista): ${countryProfile.driveSide}
            - DDI Telefônico: ${countryProfile.callingCode}
            - Moeda Oficial: ${countryProfile.currencyName}
            - Domínio de Internet (TLD): ${countryProfile.tld}
            - Idiomas Oficiais/Falados: ${countryProfile.languages}
            - Fatos de Apoio Adicionais:
              ${countryProfile.funFacts.map((fact, i) => `  * Fato ${i + 1}: ${fact}`).join('\n')}
            
            ### MODELO DE GUIA BASE ESTILÍSTICO SELECIONADO:
            - Estilo de Guia: ${selectedStyleModel.estilo}
            - Instruções de Redação: ${selectedStyleModel.instrucoes}
            
            ### FOCO DESTA PISTA ESPECÍFICA (Para garantir variedade entre as dicas sem repetir informações):
            - Tente destacar principalmente aspectos relacionados a: **${focusAspect}**.
            
            ### TAREFA DA IA:
            Escreva em poucas palavras (máximo de 1 a 2 frases curtas) uma pista enigmática e inteligente em português do Brasil com base nas informações fáticas fornecidas acima, seguindo o Estilo de Guia e o Foco sugeridos.
            Não inclua cabeçalhos, títulos ou prefixos (não escreva "Dica 1:" ou "Gastronomia:"). Vá direto ao texto da pista.
            Lembre-se: NUNCA mencione o nome do país nem de suas cidades!`;

          const response = await ai.models.generateContent({
            model: "gemini-3.5-flash",
            contents: promptText,
            config: {
              systemInstruction,
              temperature: 0.85,
            }
          });

          generatedClue = response.text?.trim() || getFallbackClueText();
        } catch (geminiError: any) {
          console.error("Gemini API call failed (using robust local profile fallback):", geminiError);
          generatedClue = getFallbackClueText();
          isFallback = true;
        }
      }

      res.json({
        clueIndex,
        category: "Dica",
        text: generatedClue,
        countryCode,
        isFallback
      });

    } catch (error: any) {
      console.error("Erro ao gerar pistas:", error);
      res.status(500).json({ error: error?.message || "Erro desconhecido ao processar dicas." });
    }
  });

  // API Route: Server Config (Expose Mapillary Token dynamically to frontend)
  app.get("/api/config", (req: Request, res: Response): void => {
    res.json({
      mapillaryToken: process.env.VITE_MAPILLARY_TOKEN || process.env.MAPILLARY_TOKEN || ""
    });
  });

  // Serve static assets in production, otherwise use Vite middleware in development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req: Request, res: Response) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`[Server] GeoGuessr Mapillary rodando na porta ${PORT}`);
  });
}

startServer();
